' Facade 패턴(김동석)
' https://github.com/bluedskim/javaDesignPatterns

class ShapeMakerTest {
  <<C>>
  ShapeMakerTest
  +void ShapeMakerFacadeTest()
}

class ShapeMaker {
  <<C>>
  ShapeMaker
  +String drawAllShape()
}

interface Shape {
  <<I>>
  Shape
  +String draw()
}

class Circle {
  <<C>>
  Circle
  +String draw()
}

class Rectangle {
  <<C>>
  Rectangle
  +String draw()
}

class Square {
  <<C>>
  Square
  +String draw()
}

ShapeMakerTest --> ShapeMaker
ShapeMaker --> Shape
Circle ..|> Shape
Rectangle ..|> Shape
Square ..|> Shape

